operation.add:
{% if banner['btn_text'] %}
    {% if banner['link'] and banner['link'] != '' %}
        {# Если ссылка указана - обычная кнопка-ссылка #}
        {% if img_link %}
            <p class="intro__item-price">{{ banner['btn_text'] }}</p>
        {% else %}
            <a href="{{ banner['link'] }}" class="intro__item-price">{{ banner['btn_text'] }}</a>
        {% endif %}
    {% else %}
        {# Если ссылка пустая - кнопка для модального окна #}
        <button onclick="ajaxCheaper('index.php?route=extension/module/cheaper30&prod_id={{ product_id|default('0') }}&module_id=70', this);" 
                data-module_id="70" 
                class="intro__item-price" 
                style="background: transparent; border: none; cursor: pointer; padding: 0; text-align: left;">
            {{ banner['btn_text'] }}
        </button>
    {% endif %}
{% endif %}

{% if banner['btn_text'] %}
    <div class="intro__item-action">
        {% if banner['link'] and banner['link'] != '' %}
            {# Обычная ссылка #}
            <span class="ui-btn ui-btn--35 ui-btn--{% if banner['text_color'] == '1' %}dark{% else %}white{% endif %} ui-btn--outline">
                {{ banner['btn_text'] }}
                <svg class="icon-arrow-btn"><use xlink:href="catalog/view/theme/prostore/sprites/sprite.svg#icon-arrow-btn"></use></svg>
            </span>
        {% else %}
            {# Модальное окно #}
            <button onclick="ajaxCheaper('index.php?route=extension/module/cheaper30&prod_id={{ product_id|default('0') }}&module_id=70', this); event.preventDefault(); event.stopPropagation();" 
                    data-module_id="70"
                    class="ui-btn ui-btn--35 ui-btn--{% if banner['text_color'] == '1' %}dark{% else %}white{% endif %} ui-btn--outline"
                    style="background: transparent; cursor: pointer;">
                {{ banner['btn_text'] }}
                <svg class="icon-arrow-btn"><use xlink:href="catalog/view/theme/prostore/sprites/sprite.svg#icon-arrow-btn"></use></svg>
            </button>
        {% else %}
    </div>
{% endif %}
